/**
 * normalize-jobs.js — body of the n8n Code node "Compile Jobs".
 * Mode: "Run Once for All Items".
 *
 * n8n Code nodes cannot require() local files, so the pure transform below is
 * INLINED from src/normalize-core.js — keep the two in sync. The only n8n-specific
 * parts are the input readers (readApiArray / readConfig) and the return shape at
 * the bottom.
 *
 * Reads the upstream nodes: "Config" (Set), "Remotive" (HTTP), "Jobicy" (HTTP),
 * "JSearch" (HTTP). Returns one n8n item per matched job (now carrying a cleaned
 * `description`, an empty `summary` for the LLM node to fill, and a `trust_score`),
 * or a single { empty: true } item when nothing matched (so the "no results" email
 * branch still fires — a node that outputs zero items would stop the workflow).
 */

// ===== BEGIN inlined core (mirror of src/normalize-core.js) =================
const DEFAULT_CONFIG = {
  allowedTypes: ['part_time', 'contract', 'freelance'],
  maxAgeDays: 30,
  requireKeyword: true,
  keywords: [
    'automation', 'automate', 'rpa', 'zapier', 'n8n', 'make.com', 'workflow',
    'integration', 'no-code', 'low-code', 'ai agent', 'artificial intelligence',
    'machine learning', 'data annotation', 'data label',
    'process automation', 'workflow automation', 'ai automation', 'agentic',
    'chatbot', 'power automate', 'uipath',
  ],
  excludeTitleKeywords: [
    'sales', 'account executive', 'account manager', 'business development',
    'recruit', 'copywriter', 'content writer', 'sdr', 'bdr',
  ],
  // HARD block: clerical roles that sometimes carry "automation" in the title but are never
  // AI-automation roles. Dropped even when the title mentions a keyword.
  blockTitleKeywords: [
    'secretary', 'receptionist', 'data entry', 'administrative assistant', 'office administrator',
    'virtual assistant', 'appointment setter', 'telemarketer', 'call center', 'cold caller',
    'customer service representative',
  ],
};

const REPUTABLE_BOARDS = [
  'linkedin', 'indeed', 'glassdoor', 'ziprecruiter', 'wellfound', 'we work remotely',
  'remotive', 'jobicy', 'dice', 'builtin', 'stack overflow', 'weworkremotely', 'greenhouse',
  'lever', 'workday',
];

function normJobType(raw) {
  if (!raw) return '';
  return String(raw).toLowerCase().trim().replace(/[\s-]+/g, '_');
}

function toDate(value) {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'number' || /^\d+$/.test(String(value))) {
    const secs = Number(value);
    const ms = secs > 1e12 ? secs : secs * 1000;
    const d = new Date(ms);
    return isNaN(d.getTime()) ? null : d;
  }
  const d = new Date(value);
  return isNaN(d.getTime()) ? null : d;
}

function stripHtml(s) {
  return String(s || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&#39;|&rsquo;|&apos;/g, "'")
    .replace(/&quot;|&ldquo;|&rdquo;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

function clip(s, n) {
  const str = String(s || '');
  if (str.length <= n) return str;
  return str.slice(0, n - 1).replace(/\s+\S*$/, '') + '…';
}

function normCompany(c) {
  return String(c || '')
    .toLowerCase()
    .replace(/[.,]/g, '')
    .replace(/\b(inc|llc|ltd|gmbh|co|corp|limited|company)\b/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

function firstAllowedType(types, allowed) {
  for (const t of types) {
    if (allowed.includes(normJobType(t))) return normJobType(t);
  }
  return '';
}

function fromRemotive(jobs) {
  return (jobs || []).map((j) => {
    const tags = Array.isArray(j.tags) ? j.tags.join(', ') : '';
    return {
      source: 'Remotive',
      title: j.title || '',
      company: j.company_name || '',
      _types: [j.job_type],
      location: j.candidate_required_location || 'Remote',
      salary: j.salary || '',
      url: j.url || '',
      _date: toDate(j.publication_date),
      tags,
      _desc: stripHtml(j.description),
      _website: '',
      _logo: j.company_logo || '',
      _direct: false,
      _hay: `${j.title || ''} ${tags} ${j.category || ''} ${j.description || ''}`,
    };
  });
}

function fromJobicy(jobs) {
  return (jobs || []).map((j) => {
    let salary = '';
    if (j.salaryMin || j.salaryMax) {
      const cur = j.salaryCurrency || '';
      salary = `${cur} ${j.salaryMin || '?'}–${j.salaryMax || '?'}`.trim();
    }
    const tags = Array.isArray(j.jobIndustry) ? j.jobIndustry.join(', ') : '';
    return {
      source: 'Jobicy',
      title: j.jobTitle || '',
      company: j.companyName || '',
      _types: Array.isArray(j.jobType) ? j.jobType : [j.jobType],
      location: j.jobGeo || 'Remote',
      salary,
      url: j.url || '',
      _date: toDate(j.pubDate),
      tags,
      _desc: stripHtml(j.jobDescription || j.jobExcerpt),
      _website: '',
      _logo: j.companyLogo || '',
      _direct: false,
      _hay: `${j.jobTitle || ''} ${tags} ${j.jobExcerpt || ''} ${j.jobDescription || ''}`,
    };
  });
}

const JSEARCH_TYPE = { FULLTIME: 'full_time', PARTTIME: 'part_time', CONTRACTOR: 'contract', INTERN: 'intern' };

function fromJSearch(jobs) {
  return (jobs || []).map((j) => {
    let salary = '';
    if (j.job_min_salary || j.job_max_salary) {
      const cur = j.job_salary_currency || '';
      const per = j.job_salary_period ? '/' + String(j.job_salary_period).toLowerCase() : '';
      salary = `${cur} ${j.job_min_salary || '?'}–${j.job_max_salary || '?'}${per}`.trim();
    }
    const loc = j.job_is_remote ? 'Remote'
      : [j.job_city, j.job_country].filter(Boolean).join(', ') || 'Remote';
    return {
      source: j.job_publisher || 'JSearch',
      title: j.job_title || '',
      company: j.employer_name || '',
      _types: (Array.isArray(j.job_employment_types) && j.job_employment_types.length
        ? j.job_employment_types
        : [j.job_employment_type]).map((t) => JSEARCH_TYPE[t] || t),
      location: loc,
      salary,
      url: j.job_apply_link || '',
      _date: toDate(j.job_posted_at_datetime_utc),
      tags: j.job_publisher || '',
      _desc: stripHtml(j.job_description),
      _website: j.employer_website || '',
      _logo: j.employer_logo || '',
      _direct: j.job_apply_is_direct === true,
      _hay: `${j.job_title || ''} ${j.job_publisher || ''} ${j.job_description || ''}`,
    };
  });
}

function matchesKeyword(row, keywords) {
  const hay = String(row._hay || `${row.title} ${row.tags}`).toLowerCase();
  return keywords.some((k) => hay.includes(k.toLowerCase()));
}

function computeTrust(row, sourceCount) {
  let score = 40;
  const reasons = [];
  if (row.salary && String(row.salary).trim()) { score += 20; reasons.push('salary disclosed'); }
  if (sourceCount >= 2) { score += 15; reasons.push(`cross-posted on ${sourceCount} boards`); }
  const days = row._date ? Math.floor((Date.now() - row._date.getTime()) / 86400000) : null;
  if (days !== null) {
    if (days <= 7) { score += 12; reasons.push('posted this week'); }
    else if (days <= 14) { score += 8; reasons.push('posted recently'); }
    else if (days <= 30) { score += 4; }
  }
  if (row._website) { score += 8; reasons.push('verified company website'); }
  if (row._logo) { score += 3; }
  if (row._direct) { score += 7; reasons.push('direct application'); }
  if (REPUTABLE_BOARDS.some((p) => String(row.source).toLowerCase().includes(p))) {
    score += 8; reasons.push('reputable job board');
  }
  score = Math.max(0, Math.min(100, score));
  const band = score >= 80 ? 'High' : score >= 60 ? 'Good' : 'Basic';
  return { score, band, reasons };
}

function buildRows(mappedBySource, config) {
  const cfg = Object.assign({}, DEFAULT_CONFIG, config || {});
  const cutoff = cfg.maxAgeDays
    ? Date.now() - cfg.maxAgeDays * 24 * 60 * 60 * 1000
    : null;
  const all = [].concat.apply([], Object.keys(mappedBySource).map((k) => mappedBySource[k]));

  const companySources = new Map();
  for (const row of all) {
    const key = normCompany(row.company);
    if (!key) continue;
    if (!companySources.has(key)) companySources.set(key, new Set());
    companySources.get(key).add(String(row.source).toLowerCase());
  }

  const seenUrl = new Set();
  const seenTitle = new Set();
  const out = [];
  for (const row of all) {
    const jobType = firstAllowedType(row._types || [], cfg.allowedTypes);
    if (!jobType) continue;
    if (cfg.requireKeyword && !matchesKeyword(row, cfg.keywords)) continue;
    const titleLc = (row.title || '').toLowerCase();
    if ((cfg.blockTitleKeywords || []).some((k) => titleLc.includes(k))) continue;
    const titleExcluded = (cfg.excludeTitleKeywords || []).some((k) => titleLc.includes(k));
    const titleOnTopic = cfg.keywords.some((k) => titleLc.includes(k.toLowerCase()));
    if (titleExcluded && !titleOnTopic) continue;
    if (cutoff && row._date && row._date.getTime() < cutoff) continue;
    // dedupe by URL OR normalized title (JSearch cross-posts one role to several boards with
    // different URLs and different employer strings, so collapse on title).
    const urlKey = (row.url || '').toLowerCase().trim();
    const titleKey = (row.title || '').toLowerCase().replace(/\s+/g, ' ').trim();
    if ((urlKey && seenUrl.has(urlKey)) || (titleKey && seenTitle.has(titleKey))) continue;
    if (urlKey) seenUrl.add(urlKey);
    if (titleKey) seenTitle.add(titleKey);

    const sourceCount = (companySources.get(normCompany(row.company)) || new Set()).size || 1;
    const trust = computeTrust(row, sourceCount);

    out.push({
      source: row.source,
      title: row.title,
      company: row.company,
      job_type: jobType,
      location: row.location,
      salary: row.salary,
      posted_date: row._date ? row._date.toISOString().slice(0, 10) : '',
      url: row.url,
      tags: row.tags,
      description: clip(row._desc || '', 400),
      summary: '',
      company_website: row._website || '',
      company_logo: row._logo || '',
      trust_score: trust.score,
      trust_band: trust.band,
      trust_reasons: trust.reasons.join('; '),
      _ts: row._date ? row._date.getTime() : 0,
    });
  }
  out.sort((a, b) => b._ts - a._ts);
  return out.map((r) => { const c = Object.assign({}, r); delete c._ts; return c; });
}
// ===== END inlined core ====================================================

// ----- n8n glue ------------------------------------------------------------

/** Pull the array at `key` from an HTTP node's JSON body; [] if node failed/missing. */
function readApiArray(nodeName, key) {
  try {
    const items = $(nodeName).all();
    if (!items.length) return [];
    const body = items[0].json || {};
    return Array.isArray(body[key]) ? body[key] : [];
  } catch (e) {
    return [];
  }
}

/**
 * JSearch's jobs array. /search-v2 nests them at `data.jobs` (data is an object);
 * the legacy /search returned `data` as the array directly. Handle both. [] on failure.
 */
function readJSearchJobs() {
  try {
    const items = $('JSearch').all();
    if (!items.length) return [];
    const body = items[0].json || {};
    const d = body.data;
    if (Array.isArray(d)) return d;                 // legacy /search
    if (d && Array.isArray(d.jobs)) return d.jobs;  // /search-v2
    return [];
  } catch (e) {
    return [];
  }
}

/** Read overrides from the "Config" Set node; falls back to code defaults. */
function readConfig() {
  let raw = {};
  try { raw = $('Config').first().json || {}; } catch (e) { raw = {}; }
  const cfg = {};
  if (raw.maxAgeDays !== undefined && raw.maxAgeDays !== '') cfg.maxAgeDays = Number(raw.maxAgeDays);
  if (raw.allowedTypes) cfg.allowedTypes = String(raw.allowedTypes).split(',').map((s) => s.trim()).filter(Boolean);
  if (raw.requireKeyword !== undefined) cfg.requireKeyword = raw.requireKeyword === true || raw.requireKeyword === 'true';
  return cfg;
}

const remotiveJobs = readApiArray('Remotive', 'jobs');
const jobicyJobs = readApiArray('Jobicy', 'jobs');
const jsearchJobs = readJSearchJobs(); // [] when the node/credential is absent

const rows = buildRows(
  {
    remotive: fromRemotive(remotiveJobs),
    jobicy: fromJobicy(jobicyJobs),
    jsearch: fromJSearch(jsearchJobs),
  },
  readConfig(),
);

if (rows.length === 0) {
  return [{ json: { empty: true, count: 0 } }];
}
return rows.map((r) => ({ json: r }));

/**
 * prep-summaries.js — body of the n8n Code node "Prep Summaries".
 * Mode: "Run Once for All Items".
 *
 * Collapses the N job items from "Compile Jobs" into ONE item so the Gemini HTTP
 * node fires a SINGLE batched call (cost stays flat regardless of job count). The
 * output item carries:
 *   - jobs:       the full job rows, untouched, for "Apply Summaries" to re-expand.
 *   - geminiBody: the exact JSON request body for Gemini's generateContent endpoint,
 *                 asking for a one-sentence summary per role as a strict JSON array.
 */

const items = $input.all().map((i) => i.json);

// Compact payload for the model — index + the minimum it needs to summarize.
const jobsForLlm = items.map((j, idx) => ({
  i: idx,
  title: j.title || '',
  company: j.company || '',
  job_type: j.job_type || '',
  location: j.location || '',
  desc: String(j.description || '').slice(0, 500),
}));

const instruction =
  'You are a job-market analyst. For EACH job object below, write ONE concise, ' +
  'factual sentence (max 22 words) that says what the role involves and, if clear, ' +
  'what the employer does. No hype, no "exciting opportunity". ' +
  'Return ONLY a JSON array like [{"i":0,"summary":"..."}] — one object per job, ' +
  'matching the "i" index. No markdown, no code fences.\n\nJobs:\n' +
  JSON.stringify(jobsForLlm);

const geminiBody = {
  contents: [{ parts: [{ text: instruction }] }],
  generationConfig: {
    temperature: 0.2,
    maxOutputTokens: 2048,
    responseMimeType: 'application/json',
  },
};

return [{ json: { jobs: items, count: items.length, geminiBody } }];

/**
 * apply-summaries.js — body of the n8n Code node "Apply Summaries".
 * Mode: "Run Once for All Items".
 *
 * Re-expands the single batched item back to one item per job, attaching the
 * one-line `summary` from Gemini. If Gemini failed, errored, or returned
 * unparseable output, each job falls back to the first sentence of its own
 * description — so the report NEVER breaks on an LLM hiccup.
 *
 * Reads "Prep Summaries" (the retained job rows) and "Gemini" (the raw response).
 */

const jobs = (() => {
  try { return $('Prep Summaries').first().json.jobs || []; } catch (e) { return []; }
})();

// Parse Gemini's JSON array of { i, summary } into an index -> summary map. Any
// failure (node errored, empty body, non-JSON, wrapped in ```json fences) => {}.
function parseSummaries() {
  const map = {};
  try {
    const resp = $('Gemini').first().json || {};
    let text =
      (resp.candidates &&
        resp.candidates[0] &&
        resp.candidates[0].content &&
        resp.candidates[0].content.parts &&
        resp.candidates[0].content.parts[0] &&
        resp.candidates[0].content.parts[0].text) || '';
    text = String(text).replace(/^```(?:json)?/i, '').replace(/```$/, '').trim();
    const arr = JSON.parse(text);
    if (Array.isArray(arr)) {
      for (const o of arr) {
        if (o && typeof o.i === 'number') map[o.i] = String(o.summary || '').trim();
      }
    }
  } catch (e) {
    // leave map empty -> everything falls back to the description snippet
  }
  return map;
}

/** First sentence of the description, else a trimmed slice, as the no-LLM fallback. */
function firstSentence(desc) {
  const d = String(desc || '').trim();
  if (!d) return '';
  const m = d.match(/^.*?[.!?](\s|$)/);
  return (m ? m[0] : d).trim().slice(0, 200);
}

const summaries = parseSummaries();

return jobs.map((j, idx) => {
  const s = summaries[idx];
  const summary = (s && s.length ? s : firstSentence(j.description)).slice(0, 200);
  return { json: Object.assign({}, j, { summary }) };
});

/**
 * build-report.js — body of the n8n Code node "Build Report".
 * Mode: "Run Once for All Items".
 *
 * Turns the summarized+scored job rows (from "Apply Summaries") into the whole
 * deliverable, in ONE place so all presentation logic is testable together:
 *   - json.chart_url : a QuickChart image URL (top companies by Trust score).
 *   - json.html      : the full HTML email body (chart + per-role cards).
 *   - json.subject   : the email subject line.
 *   - json.count     : role count (for the Data Table / logging).
 *   - binary.data    : a styled, Excel-compatible .xls (opens in Excel/Sheets with
 *                      colored headers, a colored Trust column, and clickable links).
 *
 * The .xls is an HTML table saved with an .xls extension — the only way to ship a
 * *styled* spreadsheet from n8n Cloud, which blocks external Code-node libraries
 * (exceljs) and whose "Convert to File" node can't format cells. Excel/Google Sheets
 * open it with the formatting intact.
 */

// ---------- pure helpers (kept side-effect free for offline testing) ----------

function esc(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

const BAND_COLOR = { High: '#16a34a', Good: '#d97706', Basic: '#6b7280' };
const BAND_BG = { High: '#dcfce7', Good: '#fef3c7', Basic: '#f3f4f6' };

/** QuickChart horizontal bar of the top companies by (max) Trust score. */
function buildChartUrl(jobs) {
  const byCompany = {};
  for (const j of jobs) {
    const c = j.company || 'Unknown';
    const band = j.trust_band || 'Basic';
    if (!byCompany[c] || j.trust_score > byCompany[c].score) {
      byCompany[c] = { score: j.trust_score || 0, band };
    }
  }
  const top = Object.keys(byCompany)
    .map((c) => ({ company: c, score: byCompany[c].score, band: byCompany[c].band }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 8);

  const config = {
    type: 'horizontalBar',
    data: {
      labels: top.map((t) => (t.company.length > 26 ? t.company.slice(0, 25) + '…' : t.company)),
      datasets: [{
        label: 'Trust score',
        data: top.map((t) => t.score),
        backgroundColor: top.map((t) => BAND_COLOR[t.band] || BAND_COLOR.Basic),
        borderWidth: 0,
      }],
    },
    options: {
      legend: { display: false },
      title: { display: true, text: 'Company Trust Score (0–100)', fontSize: 16 },
      scales: { xAxes: [{ ticks: { beginAtZero: true, max: 100, stepSize: 20 } }] },
    },
  };
  return 'https://quickchart.io/chart?w=600&h=320&bkg=white&c=' +
    encodeURIComponent(JSON.stringify(config));
}

// Palette for the initial-avatar background, picked deterministically from the name.
const AVATAR_BG = ['#4f46e5', '#0891b2', '#059669', '#d97706', '#dc2626', '#7c3aed', '#db2777'];

/** A small round avatar with the company's initial. We deliberately DON'T hotlink the
 *  employer logo — several boards (e.g. Remotive) 403 hotlinked logos, which renders as
 *  a broken image in the email. A colored initial is always reliable. */
function avatar(job) {
  const name = (job.company || '?').trim();
  const initial = esc(name.charAt(0).toUpperCase() || '?');
  let h = 0;
  for (let i = 0; i < name.length; i++) h = (h * 31 + name.charCodeAt(i)) >>> 0;
  const bg = AVATAR_BG[h % AVATAR_BG.length];
  return '<div style="width:40px;height:40px;border-radius:8px;background:' + bg + ';color:#fff;' +
    'font:600 18px sans-serif;text-align:center;line-height:40px">' + initial + '</div>';
}

function trustBadge(job) {
  const band = job.trust_band || 'Basic';
  return '<span style="display:inline-block;padding:2px 10px;border-radius:999px;font:600 12px sans-serif;' +
    'color:' + (BAND_COLOR[band] || BAND_COLOR.Basic) + ';background:' + (BAND_BG[band] || BAND_BG.Basic) +
    '">Trust ' + esc(job.trust_score) + ' · ' + esc(band) + '</span>';
}

function jobCard(job) {
  const meta = [job.job_type, job.location, job.posted_date, job.salary]
    .filter(Boolean).map(esc).join(' &nbsp;·&nbsp; ');
  return '' +
    '<tr><td style="padding:16px 0;border-bottom:1px solid #eee">' +
    '<table width="100%" cellpadding="0" cellspacing="0"><tr>' +
    '<td width="52" valign="top">' + avatar(job) + '</td>' +
    '<td valign="top">' +
    '<div style="font:600 16px sans-serif;color:#111">' +
    '<a href="' + esc(job.url) + '" style="color:#4f46e5;text-decoration:none">' + esc(job.title) + '</a></div>' +
    '<div style="font:400 14px sans-serif;color:#374151;margin:2px 0 6px">' + esc(job.company) +
    ' &nbsp; ' + trustBadge(job) + '</div>' +
    '<div style="font:400 13px sans-serif;color:#6b7280;margin-bottom:6px">' + meta + '</div>' +
    '<div style="font:400 14px sans-serif;color:#111;line-height:1.45">' + esc(job.summary || job.description) + '</div>' +
    (job.trust_reasons ? '<div style="font:400 12px sans-serif;color:#9ca3af;margin-top:6px">✓ ' +
      esc(job.trust_reasons) + '</div>' : '') +
    '<div style="margin-top:10px"><a href="' + esc(job.url) + '" ' +
    'style="display:inline-block;padding:7px 14px;background:#4f46e5;color:#fff;border-radius:6px;' +
    'font:600 13px sans-serif;text-decoration:none">Apply →</a></div>' +
    '</td></tr></table></td></tr>';
}

function buildEmailHtml(jobs, reportDate, chartUrl) {
  const count = jobs.length;
  const avg = count ? Math.round(jobs.reduce((s, j) => s + (j.trust_score || 0), 0) / count) : 0;
  const high = jobs.filter((j) => (j.trust_band || '') === 'High').length;
  const CARD_LIMIT = 12;
  const shown = jobs.slice(0, CARD_LIMIT);
  const cards = shown.map(jobCard).join('');
  const more = count > CARD_LIMIT
    ? '<p style="font:400 14px sans-serif;color:#6b7280;text-align:center;margin:16px 0">' +
      '…and ' + (count - CARD_LIMIT) + ' more in the attached Excel file.</p>'
    : '';

  function stat(label, value) {
    return '<td align="center" style="padding:10px">' +
      '<div style="font:700 22px sans-serif;color:#111">' + value + '</div>' +
      '<div style="font:400 12px sans-serif;color:#6b7280">' + label + '</div></td>';
  }

  return '' +
    '<div style="background:#f3f4f6;padding:24px 0;font-family:sans-serif">' +
    '<div style="max-width:640px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden;' +
    'box-shadow:0 1px 3px rgba(0,0,0,.08)">' +

    // header
    '<div style="background:#4f46e5;padding:24px 28px">' +
    '<div style="font:700 20px sans-serif;color:#fff">Weekly AI-Automation Jobs</div>' +
    '<div style="font:400 14px sans-serif;color:#c7d2fe;margin-top:4px">' +
    'Part-time · contract · freelance &nbsp;|&nbsp; ' + esc(reportDate) + '</div></div>' +

    // stat row
    '<table width="100%" cellpadding="0" cellspacing="0" style="border-bottom:1px solid #eee">' +
    '<tr>' + stat('roles', count) + stat('avg trust', avg + '/100') + stat('high trust', high) + '</tr></table>' +

    // chart
    '<div style="padding:20px 28px 4px;text-align:center">' +
    '<div style="font:600 14px sans-serif;color:#374151;margin-bottom:8px;text-align:left">' +
    'Which employers look most legitimate?</div>' +
    '<img src="' + esc(chartUrl) + '" width="600" style="max-width:100%;border:1px solid #eee;border-radius:8px" alt="Company Trust Score chart">' +
    '<div style="font:400 11px sans-serif;color:#9ca3af;margin:6px 0 0;text-align:left">' +
    'Trust score is a transparency signal (salary shown, cross-posting, verified site, recency, reputable board) — not an official employer rating.</div>' +
    '</div>' +

    // cards
    '<div style="padding:8px 28px 20px"><table width="100%" cellpadding="0" cellspacing="0">' +
    cards + '</table>' + more + '</div>' +

    // footer
    '<div style="padding:16px 28px;background:#fafafa;border-top:1px solid #eee;' +
    'font:400 12px sans-serif;color:#9ca3af">Sources: Remotive, Jobicy, JSearch ' +
    '(Indeed / LinkedIn / Glassdoor / ZipRecruiter via Google for Jobs). ' +
    'Summaries by Google Gemini. Generated automatically by n8n.</div>' +

    '</div></div>';
}

/** Styled Excel-compatible .xls (HTML table). Opens in Excel/Sheets with formatting. */
function buildXlsHtml(jobs, reportDate) {
  const count = jobs.length;
  const avg = count ? Math.round(jobs.reduce((s, j) => s + (j.trust_score || 0), 0) / count) : 0;
  const high = jobs.filter((j) => (j.trust_band || '') === 'High').length;
  const good = jobs.filter((j) => (j.trust_band || '') === 'Good').length;
  const basic = count - high - good;

  const cols = [
    { k: 'trust_score', h: 'Trust', w: 60 },
    { k: 'trust_band', h: 'Band', w: 60 },
    { k: 'title', h: 'Title', w: 260 },
    { k: 'company', h: 'Company', w: 180 },
    { k: 'job_type', h: 'Type', w: 90 },
    { k: 'location', h: 'Location', w: 150 },
    { k: 'salary', h: 'Salary', w: 130 },
    { k: 'posted_date', h: 'Posted', w: 90 },
    { k: 'summary', h: 'Summary', w: 360 },
    { k: 'source', h: 'Source', w: 120 },
  ];
  const thStyle = 'background:#4f46e5;color:#fff;font:600 12px sans-serif;padding:8px;' +
    'border:1px solid #4338ca;text-align:left';
  const head = '<tr>' + cols.map((c) =>
    '<th style="' + thStyle + ';width:' + c.w + 'px">' + esc(c.h) + '</th>').join('') +
    '<th style="' + thStyle + '">Link</th></tr>';

  const rows = jobs.map((j, idx) => {
    const zebra = idx % 2 ? '#f8fafc' : '#ffffff';
    const cells = cols.map((c) => {
      let v = j[c.k];
      let style = 'padding:6px 8px;border:1px solid #e5e7eb;font:400 12px sans-serif;' +
        'background:' + zebra + ';vertical-align:top';
      if (c.k === 'trust_band' || c.k === 'trust_score') {
        style += ';font-weight:600;color:' + (BAND_COLOR[j.trust_band] || BAND_COLOR.Basic) +
          ';background:' + (BAND_BG[j.trust_band] || BAND_BG.Basic) + ';text-align:center';
      }
      if (c.k === 'title') {
        return '<td style="' + style + '"><a href="' + esc(j.url) + '">' + esc(v) + '</a></td>';
      }
      return '<td style="' + style + '">' + esc(v) + '</td>';
    }).join('');
    const link = '<td style="padding:6px 8px;border:1px solid #e5e7eb;font:400 12px sans-serif;' +
      'background:' + zebra + '"><a href="' + esc(j.url) + '">open</a></td>';
    return '<tr>' + cells + link + '</tr>';
  }).join('');

  const span = cols.length + 1; // +1 for the Link column
  const banner = '<tr><td colspan="' + span + '" style="background:#312e81;color:#fff;' +
    'font:700 18px sans-serif;padding:14px 10px;border:1px solid #312e81">' +
    'Weekly AI-Automation Jobs &nbsp;·&nbsp; Part-time / Contract / Freelance &nbsp;·&nbsp; ' + esc(reportDate) +
    '</td></tr>';
  const summary = '<tr><td colspan="' + span + '" style="background:#eef2ff;color:#3730a3;' +
    'font:600 13px sans-serif;padding:8px 10px;border:1px solid #c7d2fe">' +
    count + ' roles &nbsp;·&nbsp; avg trust ' + avg + '/100 &nbsp;·&nbsp; ' +
    high + ' High · ' + good + ' Good · ' + basic + ' Basic &nbsp;·&nbsp; ' +
    'Sources: Remotive, Jobicy, JSearch</td></tr>';
  const legend = '<tr><td colspan="' + span + '" style="background:#ffffff;color:#6b7280;' +
    'font:400 11px sans-serif;padding:6px 10px;border:1px solid #e5e7eb">' +
    'Trust bands: High ≥ 80 &nbsp; Good 60–79 &nbsp; Basic &lt; 60 &nbsp; — a transparency signal ' +
    '(salary shown, cross-posting, verified site, recency, reputable board), not an official rating.</td></tr>';
  const spacer = '<tr><td colspan="' + span + '" style="height:8px"></td></tr>';

  return '<html><head><meta charset="utf-8"></head><body>' +
    '<table border="0" cellspacing="0" cellpadding="0" style="border-collapse:collapse">' +
    banner + summary + legend + spacer + head + rows + '</table></body></html>';
}

// ---------- n8n glue ----------

const jobs = $input.all().map((i) => i.json);
const reportDate = new Date().toISOString().slice(0, 10);

const chartUrl = buildChartUrl(jobs);
const html = buildEmailHtml(jobs, reportDate, chartUrl);
const subject = 'Weekly AI Automation Jobs — ' + reportDate + ' (' + jobs.length + ' roles)';
const xlsHtml = buildXlsHtml(jobs, reportDate);

// Styled spreadsheet (binary property `data`).
const xlsBinary = await this.helpers.prepareBinaryData(
  Buffer.from(xlsHtml, 'utf8'),
  'ai-automation-jobs.xls',
  'application/vnd.ms-excel',
);

// The Trust chart as its own PNG file (binary property `chart`), so it's a standalone
// attachment in addition to being embedded in the email body. On any fetch failure we fall
// back to a 1x1 PNG so the email's chart attachment can never error the send.
let chartBinary;
try {
  const png = await this.helpers.httpRequest({ url: chartUrl, encoding: 'arraybuffer' });
  chartBinary = await this.helpers.prepareBinaryData(Buffer.from(png), 'company-trust-chart.png', 'image/png');
} catch (e) {
  const px = Buffer.from(
    'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNk+M9QDwADhgGAWjR9awAAAABJRU5ErkJggg==',
    'base64',
  );
  chartBinary = await this.helpers.prepareBinaryData(px, 'company-trust-chart.png', 'image/png');
}

return [{
  json: { subject, html, chart_url: chartUrl, count: jobs.length, report_date: reportDate },
  binary: { data: xlsBinary, chart: chartBinary },
}];
